            aOrbiterB = (aOrbiterB ^ aOrbiterD) ^ 0xF66C3790A64926CEULL;
            aOrbiterB = RotL64((aOrbiterB * 0xDAC357EA4DEADEA9ULL), 13U);
            //
            aIngress = aOrbiterD ^ RotL64(aOrbiterF, 54U);
            aIngress = aIngress + (aOrbiterG ^ RotL64(aOrbiterB, 51U));
            aIngress = aIngress + (RotL64(aOrbiterH, 57U) ^ aOrbiterI);
            aIngress = aIngress + (RotL64(aOrbiterA, 3U) ^ aOrbiterC);
            aIngress = aIngress + RotL64(aOrbiterE, 39U);
            aIngress = TwistMix64::DiffuseB((aIngress + aScatter));
            //
            aWandererD = aWandererD + ((RotL64(aScatter, 21U) + aOrbiterH) + RotL64(aOrbiterA, 5U));
