        //
        // twist_loop_g loop 6
        //
        // Ingress:
        //      aWorkLaneC (-->), aWorkLaneA (-->), aSnowLaneC (-->), aInvestLaneA (<-?->)
        //
        // Cross:
        //      aWorkLaneB (<--), aEarthLaneB (<--), aInvestLaneB (<-?->)
        //
        // Destination:
        //      aWorkLaneD
