            aOrbiterB = (aOrbiterB + aOrbiterD) + 0x528EB0AD2146B858ULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterB) ^ 0x78EA6DD56301C7B5ULL;
            aOrbiterE = RotL64((aOrbiterE * 0xF13DF56633EE6E91ULL), 19U);
            //
            aIngress = aOrbiterJ ^ RotL64(aOrbiterK, 23U);
