            //
            aWandererI = aWandererI ^ ((RotL64(aPrevious, 46U) + aOrbiterC) + RotL64(aOrbiterB, 21U));
            aWandererG = aWandererG + ((RotL64(aIngress, 57U) + RotL64(aOrbiterE, 13U)) + aOrbiterK);
